mapper.insert:
	INSERT INTO XBOLTADM.TB_VISIT_LOG /*insertVisitLog*/ (
		MemberID, TeamID, Time, ItemID, MenuID, ClientID , ActionType					
 		
			,IpAddress
		
 		
			,source
		
		
			,Comment
		
		
			,InstanceNo
		
	)
	VALUES(
		#{sessionUserId}, #{sessionTeamId}, getDate(), #{ItemId}, #{MenuID}, #{sessionClientId} , #{ActionType}			
 		
			,#{IpAddress}
		
 		
			,#{source}
		
		
			,#{comment}
		
		
			,#{instanceNo}
		
	)

mapper.select:
	   SELECT
	   		
	   			
	   				Top ${top} *
	   			
	   			
	   				Count(*) cnt
	   			
	   		
	   FROM XBOLTADM.TB_VISIT_LOG
 	   WHERE 1=1
 	   
 	   		AND ActionType = #{ActionType}
 	   
 	   
 	   		AND TIME BETWEEN #{scStartDt} AND #{scEndDt}
 	   
 	   
 	   		AND IpAddress = #{IpAddress}
   		
 	   	
 	   		AND MemberID = #{sessionUserId}
   		
   		
   			Order by SEQ DESC
